public void modifiedField(fieldId _fieldId)
{

    InventTable inventTable;
    next modifiedField(_fieldId);
    switch (_fieldId)
    {
        case fieldNum(AgreementLine, ItemId):
            // Logic to execute when MyLookupField is modified
            select InventTable where InventTable.ItemId == this.ItemId;

            this.ETGMainCommodity = InventTable.ETGCommodity;



            break;

    }

}
